/**
 * Top navigation bar — deliberately minimal per the spec.
 * Wordmark on the left, About + History affordances on the right.
 */

import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { History, Sparkles, Info } from 'lucide-react';

interface Props {
  onOpenHistory: () => void;
}

export const NavBar: React.FC<Props> = ({ onOpenHistory }) => {
  const location = useLocation();
  const onHome = location.pathname === '/';

  return (
    <header className="sticky top-0 z-40 bg-bg-base/80 backdrop-blur-md border-b border-border-subtle">
      <div className="mx-auto flex max-w-6xl items-center justify-between px-md py-3 md:px-lg md:py-4">
        <Link
          to="/"
          className="flex items-center gap-sm text-ink-primary hover:opacity-90 transition"
          data-testid="nav-wordmark"
        >
          <span className="grid h-8 w-8 place-items-center rounded-xl bg-gradient-to-br from-accent to-accent-soft shadow-lg shadow-accent/30">
            <Sparkles size={16} className="text-bg-base" />
          </span>
          <span className="font-display text-lg font-semibold tracking-tight">
            CodeExplain
          </span>
        </Link>

        <nav className="flex items-center gap-1">
          {onHome && (
            <button
              onClick={onOpenHistory}
              className="inline-flex items-center gap-sm rounded-pill px-md py-2 text-pill text-ink-secondary hover:text-ink-primary hover:bg-white/[0.05] transition-colors"
              data-testid="nav-history-btn"
            >
              <History size={14} />
              <span className="hidden sm:inline">History</span>
            </button>
          )}
          <Link
            to="/about"
            className={`inline-flex items-center gap-sm rounded-pill px-md py-2 text-pill transition-colors ${
              location.pathname === '/about'
                ? 'text-ink-primary bg-white/[0.06]'
                : 'text-ink-secondary hover:text-ink-primary hover:bg-white/[0.05]'
            }`}
            data-testid="nav-about-link"
          >
            <Info size={14} />
            <span className="hidden sm:inline">About</span>
          </Link>
        </nav>
      </div>
    </header>
  );
};
